"""
Stores: web views + REST API endpoints.
"""
from flask import Blueprint, jsonify, request, abort, current_app, render_template
from app.services import entity_service

stores_bp = Blueprint('stores', __name__)


# ---------------------------------------------------------------------------
# Views (text placeholder — HTML templates to be added in Issue #4)
# ---------------------------------------------------------------------------

@stores_bp.route('/stores')
def stores_list():
    return render_template('stores/list.html')


@stores_bp.route('/stores/map')
def stores_map():
    stores = entity_service.get_stores()
    return render_template('stores/map.html', stores=stores)


@stores_bp.route('/stores/<store_id>')
def store_detail(store_id):
    store = entity_service.get_store(store_id)
    if store is None:
        abort(404, description=f"Store '{store_id}' not found")
    inventory_groups = entity_service.get_store_inventory_grouped(store_id)
    return render_template('stores/detail.html', store=store, inventory_groups=inventory_groups)


# ---------------------------------------------------------------------------
# API — list + create
# ---------------------------------------------------------------------------

@stores_bp.route('/api/stores', methods=['GET'])
def api_stores_list():
    return jsonify(entity_service.get_stores())


@stores_bp.route('/api/stores', methods=['POST'])
def api_stores_create():
    data = request.get_json(silent=True)
    if not data:
        abort(400, description="JSON request body required")
    try:
        store = entity_service.create_store(data)
        return jsonify(store), 201
    except ValueError as e:
        abort(400, description=str(e))
    except Exception as e:
        current_app.logger.error(f"create_store: {e}")
        abort(500)


# ---------------------------------------------------------------------------
# API — detail + update + delete
# ---------------------------------------------------------------------------

@stores_bp.route('/api/stores/<store_id>', methods=['GET'])
def api_store_detail(store_id):
    store = entity_service.get_store(store_id)
    if store is None:
        abort(404, description=f"Store '{store_id}' not found")
    return jsonify(store)


@stores_bp.route('/api/stores/<store_id>/inventory-grouped', methods=['GET'])
def api_store_inventory_grouped(store_id):
    store = entity_service.get_store(store_id)
    if store is None:
        abort(404, description=f"Store '{store_id}' not found")
    return jsonify(entity_service.get_store_inventory_grouped(store_id))


@stores_bp.route('/api/stores/<store_id>', methods=['PUT'])
def api_store_update(store_id):
    data = request.get_json(silent=True)
    if not data:
        abort(400, description="JSON request body required")
    try:
        store = entity_service.update_store(store_id, data)
        if store is None:
            abort(404, description=f"Store '{store_id}' not found")
        return jsonify(store)
    except ValueError as e:
        abort(400, description=str(e))
    except Exception as e:
        current_app.logger.error(f"update_store: {e}")
        abort(500)


@stores_bp.route('/api/stores/<store_id>', methods=['DELETE'])
def api_store_delete(store_id):
    if not entity_service.delete_store(store_id):
        abort(404, description=f"Store '{store_id}' not found")
    return jsonify({"message": f"Store '{store_id}' deleted"})

{% extends "base.html" %}

{% block title %}Stores Map — FIWARE Smart Store{% endblock %}

{% block content %}
<div class="section-header stores-map-header">
  <h1 data-i18n="page_stores_map_title">Mapa de Tiendas</h1>
  <p data-i18n="page_stores_map_subtitle">Vista geográfica de todas las tiendas</p>
</div>

<div class="stores-map-card">
  <div id="stores-map-canvas" class="stores-map-canvas" role="region" aria-label="Stores map"></div>
</div>
{% endblock %}

{% block extra_scripts %}
<script>
  (function () {
    'use strict';

    var stores = {{ stores|default([], true)|tojson }};
    var mapEl = document.getElementById('stores-map-canvas');
    if (!mapEl || typeof L === 'undefined') return;

    function t(key, fallback) {
      if (!window.i18n || typeof window.i18n.t !== 'function') return fallback || key;
      var text = window.i18n.t(key);
      return text === key ? (fallback || key) : text;
    }

    function escapeHtml(value) {
      return String(value == null ? '' : value)
        .replace(/&/g, '&amp;')
        .replace(/</g, '&lt;')
        .replace(/>/g, '&gt;')
        .replace(/\"/g, '&quot;')
        .replace(/'/g, '&#39;');
    }

    function storeFallbackImage(store) {
      var countryCode = String(store && store.countryCode || '').toUpperCase();
      var imagesByCountry = {
        DE: 'https://images.unsplash.com/photo-1556742049-0cfed4f6a45d',
        ES: 'https://images.unsplash.com/photo-1542838132-92c53300491e',
        FR: 'https://images.unsplash.com/photo-1604719312566-8912e9227c6a',
        PT: 'https://images.unsplash.com/photo-1578916171728-46686eac8d58',
        IT: 'https://images.unsplash.com/photo-1579113800032-c38bd7635818',
        UK: 'https://images.unsplash.com/photo-1514933651103-005eec06c04b',
        US: 'https://images.unsplash.com/photo-1441986300917-64674bd600d8'
      };
      return imagesByCountry[countryCode] || 'https://images.unsplash.com/photo-1556740749-887f6717d7e4';
    }

    function parseLocation(location) {
      if (!location || typeof location !== 'object') return null;
      var coords = location.coordinates;
      if (!Array.isArray(coords) || coords.length < 2) return null;
      var lon = Number(coords[0]);
      var lat = Number(coords[1]);
      if (Number.isNaN(lat) || Number.isNaN(lon)) return null;
      if (lat < -90 || lat > 90 || lon < -180 || lon > 180) return null;
      return { lat: lat, lon: lon };
    }

    function formatAddress(address) {
      if (!address) return '-';
      if (typeof address === 'string') return address;
      if (typeof address !== 'object') return '-';

      var parts = [
        address.streetAddress,
        address.addressLocality,
        address.addressRegion,
        address.postalCode
      ].filter(Boolean);

      return parts.length ? parts.join(', ') : '-';
    }

    function formatHumidity(value) {
      var parsed = Number(value);
      if (Number.isNaN(parsed)) return '-';
      return (parsed * 100).toFixed(0) + '%';
    }

    function formatTemperature(value) {
      var parsed = Number(value);
      if (Number.isNaN(parsed)) return '-';
      return parsed.toFixed(1) + '°C';
    }

    function isDarkTheme() {
      return document.documentElement.getAttribute('data-theme') === 'dark';
    }

    var lightTileUrl = 'https://{s}.basemaps.cartocdn.com/light_all/{z}/{x}/{y}{r}.png';
    var darkTileUrl = 'https://{s}.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png';
    var tileAttribution = '&copy; OpenStreetMap contributors &copy; CARTO';

    var map = L.map(mapEl, {
      zoomControl: true,
      worldCopyJump: true
    });

    var tileLayer = null;
    function refreshTileLayer() {
      var nextUrl = isDarkTheme() ? darkTileUrl : lightTileUrl;
      if (tileLayer) map.removeLayer(tileLayer);
      tileLayer = L.tileLayer(nextUrl, {
        maxZoom: 19,
        attribution: tileAttribution
      });
      tileLayer.addTo(map);
    }

    refreshTileLayer();

    function markerIcon(imageUrl) {
      return L.divIcon({
        className: 'store-map-marker-wrapper',
        iconSize: [54, 54],
        iconAnchor: [27, 44],
        popupAnchor: [0, -36],
        html: '<div class="store-map-marker">'
          + '<img src="' + escapeHtml(imageUrl) + '" alt="Store" loading="lazy" referrerpolicy="no-referrer" />'
          + '</div>'
      });
    }

    function tooltipHtml(store) {
      var image = store.image || storeFallbackImage(store);
      var countryCode = String(store.countryCode || '').toUpperCase();
      var flagUrl = countryCode && /^[A-Z]{2}$/.test(countryCode)
        ? 'https://flagcdn.com/w40/' + countryCode.toLowerCase() + '.png'
        : '';

      return '<div class="store-map-tooltip-card">'
        + '<img class="store-map-tooltip-image" src="' + escapeHtml(image) + '" alt="' + escapeHtml(store.name || 'Store') + '" loading="lazy" referrerpolicy="no-referrer" />'
        + '<div class="store-map-tooltip-body">'
          + '<h3>' + escapeHtml(store.name || '-') + '</h3>'
          + '<p><i class="fas fa-location-dot" aria-hidden="true"></i> ' + escapeHtml(formatAddress(store.address)) + '</p>'
          + '<p>'
            + (flagUrl ? '<img class="store-map-flag" src="' + escapeHtml(flagUrl) + '" alt="' + escapeHtml(countryCode) + '" /> ' : '🏳️ ')
            + '<span>' + escapeHtml(countryCode || '-') + '</span>'
          + '</p>'
          + '<p><i class="fas fa-temperature-half" aria-hidden="true"></i> '
            + escapeHtml(t('stores_col_temperature', 'Temperatura')) + ': '
            + '<strong>' + escapeHtml(formatTemperature(store.temperature)) + '</strong></p>'
          + '<p><i class="fas fa-droplet" aria-hidden="true"></i> '
            + escapeHtml(t('stores_col_humidity', 'Humedad Relativa')) + ': '
            + '<strong>' + escapeHtml(formatHumidity(store.relativeHumidity)) + '</strong></p>'
          + '<p class="store-map-tooltip-hint"><i class="fas fa-arrow-pointer" aria-hidden="true"></i> '
            + escapeHtml(t('stores_map_click_to_open', 'Click para abrir detalle')) + '</p>'
        + '</div>'
      + '</div>';
    }

    var bounds = [];
    var validStores = 0;

    stores.forEach(function (store) {
      if (!store || !store.id) return;
      var pos = parseLocation(store.location);
      if (!pos) return;

      var image = store.image || storeFallbackImage(store);
      var marker = L.marker([pos.lat, pos.lon], { icon: markerIcon(image), keyboard: true });

      marker.bindTooltip(tooltipHtml(store), {
        direction: 'top',
        sticky: true,
        className: 'store-map-tooltip',
        opacity: 1
      });

      marker.on('mouseover', function () {
        marker.openTooltip();
      });
      marker.on('mouseout', function () {
        marker.closeTooltip();
      });
      marker.on('click', function () {
        window.location.href = '/stores/' + encodeURIComponent(store.id);
      });

      marker.addTo(map);
      bounds.push([pos.lat, pos.lon]);
      validStores += 1;
    });

    if (bounds.length > 0) {
      map.fitBounds(bounds, { padding: [34, 34], maxZoom: 13 });
    } else {
      map.setView([40.4168, -3.7038], 5);
      L.control({ position: 'topright' }).onAdd = function () {
        var div = L.DomUtil.create('div', 'store-map-empty-msg');
        div.innerHTML = '<i class="fas fa-circle-info" aria-hidden="true"></i> '
          + escapeHtml(t('stores_map_no_coordinates', 'No hay tiendas con coordenadas válidas para mostrar en el mapa.'));
        return div;
      }.addTo(map);
    }

    setTimeout(function () {
      map.invalidateSize();
    }, 120);

    var observer = new MutationObserver(function () {
      refreshTileLayer();
      setTimeout(function () { map.invalidateSize(); }, 60);
    });

    observer.observe(document.documentElement, {
      attributes: true,
      attributeFilter: ['data-theme']
    });

    window.addEventListener('i18n:updated', function () {
      // Re-render tooltips with translated labels when language changes.
      map.eachLayer(function (layer) {
        if (layer instanceof L.Marker && layer.getTooltip && layer.options && layer.options.keyboard) {
          var latLng = layer.getLatLng();
          var match = stores.find(function (store) {
            var pos = parseLocation(store.location);
            return pos && Math.abs(pos.lat - latLng.lat) < 1e-9 && Math.abs(pos.lon - latLng.lng) < 1e-9;
          });
          if (match) {
            layer.setTooltipContent(tooltipHtml(match));
          }
        }
      });
      if (validStores === 0) {
        var emptyMsg = document.querySelector('.store-map-empty-msg');
        if (emptyMsg) {
          emptyMsg.innerHTML = '<i class="fas fa-circle-info" aria-hidden="true"></i> '
            + escapeHtml(t('stores_map_no_coordinates', 'No hay tiendas con coordenadas válidas para mostrar en el mapa.'));
        }
      }
    });
  }());
</script>
{% endblock %}

/* ============================================================
   theme.css — CSS-first theming via data-theme attribute
   All colors are declared as CSS custom properties.
   JS only toggles [data-theme] on <html> and persists to localStorage.
   ============================================================ */

/* ---------- Light theme (default) ---------- */
:root,
:root[data-theme="light"] {
  --bg:           #f4f4f9;
  --bg-alt:       #ffffff;
  --bg-nav:       #1a1a2e;
  --fg:           #1a1a2e;
  --fg-muted:     #555577;
  --accent:       #4a90d9;
  --accent-hover: #2f72bb;
  --border:       #d0d0e0;
  --shadow:       rgba(0, 0, 0, 0.08);
  --nav-fg:       #e0e0f0;
  --nav-active:   #4a90d9;
  --nav-hover-bg: rgba(255, 255, 255, 0.08);
  --footer-bg:    #1a1a2e;
  --footer-fg:    #a0a0c0;
  --btn-bg:       #4a90d9;
  --btn-fg:       #ffffff;
  --btn-border:   transparent;
  --card-bg:      #ffffff;
  --card-shadow:  0 4px 12px rgba(0, 0, 0, 0.08);
  --badge-bg:     #e8f0fb;
  --badge-fg:     #2f72bb;
}

/* ---------- Dark theme ---------- */
:root[data-theme="dark"] {
  --bg:           #0f0f1a;
  --bg-alt:       #1a1a2e;
  --bg-nav:       #0a0a14;
  --fg:           #e0e0f0;
  --fg-muted:     #8888aa;
  --accent:       #5ba3f5;
  --accent-hover: #7dbcff;
  --border:       #2a2a40;
  --shadow:       rgba(0, 0, 0, 0.4);
  --nav-fg:       #c0c0e0;
  --nav-active:   #5ba3f5;
  --nav-hover-bg: rgba(255, 255, 255, 0.05);
  --footer-bg:    #0a0a14;
  --footer-fg:    #666688;
  --btn-bg:       #2a3a5a;
  --btn-fg:       #c0d8ff;
  --btn-border:   #3a4a7a;
  --card-bg:      #1a1a2e;
  --card-shadow:  0 4px 12px rgba(0, 0, 0, 0.4);
  --badge-bg:     #1e2a40;
  --badge-fg:     #7dbcff;
}

/* ============================================================
   Base reset & common styles
   ============================================================ */

*,
*::before,
*::after {
  box-sizing: border-box;
}

html {
  scroll-behavior: smooth;
}

body {
  margin: 0;
  font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
  font-size: 16px;
  line-height: 1.6;
  background-color: var(--bg);
  color: var(--fg);
  transition: background-color 0.25s ease, color 0.25s ease;
  min-height: 100vh;
  display: flex;
  flex-direction: column;
}

a {
  color: var(--accent);
  text-decoration: none;
}

a:hover {
  color: var(--accent-hover);
  text-decoration: underline;
}

/* ============================================================
   Navbar
   ============================================================ */

.navbar {
  position: sticky;
  top: 0;
  z-index: 1000;
  background-color: var(--bg-nav);
  color: var(--nav-fg);
  box-shadow: 0 2px 8px var(--shadow);
  transition: background-color 0.25s ease;
}

.navbar-inner {
  display: flex;
  align-items: center;
  max-width: 1280px;
  margin: 0 auto;
  padding: 0 1.5rem;
  height: 3.5rem;
  gap: 0.5rem;
}

.navbar-brand {
  font-size: 1.1rem;
  font-weight: 700;
  color: var(--nav-fg);
  white-space: nowrap;
  margin-right: 1.5rem;
  text-decoration: none;
  letter-spacing: 0.03em;
}

.navbar-brand:hover {
  color: var(--nav-active);
  text-decoration: none;
}

.navbar-brand i {
  margin-right: 0.4rem;
  color: var(--nav-active);
}

.navbar-links {
  display: flex;
  align-items: center;
  list-style: none;
  margin: 0;
  padding: 0;
  gap: 0.25rem;
  flex: 1;
}

.navbar-links li a {
  display: inline-flex;
  align-items: center;
  gap: 0.4rem;
  padding: 0.4rem 0.85rem;
  border-radius: 6px;
  color: var(--nav-fg);
  font-size: 0.9rem;
  font-weight: 500;
  white-space: nowrap;
  transition: background-color 0.15s ease, color 0.15s ease;
  text-decoration: none;
}

.navbar-links li a:hover {
  background-color: var(--nav-hover-bg);
  color: var(--nav-active);
  text-decoration: none;
}

/* Active link — set by JS via class "active" */
.navbar-links li a.active {
  color: var(--nav-active);
  border-bottom: 2px solid var(--nav-active);
  font-weight: 700;
}

/* ---- Toggle buttons ---- */
.navbar-controls {
  display: flex;
  align-items: center;
  gap: 0.5rem;
  margin-left: auto;
}

.btn-toggle {
  display: inline-flex;
  align-items: center;
  gap: 0.35rem;
  padding: 0.35rem 0.75rem;
  border-radius: 6px;
  background-color: var(--btn-bg);
  color: var(--btn-fg);
  border: 1px solid var(--btn-border);
  font-size: 0.82rem;
  font-weight: 600;
  cursor: pointer;
  transition: background-color 0.15s ease, color 0.15s ease, border-color 0.15s ease;
  white-space: nowrap;
}

.btn-toggle:hover {
  background-color: var(--accent);
  color: #fff;
  border-color: var(--accent);
}

/* Hide the light-icon when in light mode and dark-icon when in dark mode */
:root[data-theme="light"] #icon-dark  { display: inline; }
:root[data-theme="light"] #icon-light { display: none; }
:root[data-theme="dark"]  #icon-dark  { display: none; }
:root[data-theme="dark"]  #icon-light { display: inline; }

/* ============================================================
   Main content wrapper
   ============================================================ */

.main-content {
  flex: 1;
  max-width: 1280px;
  width: 100%;
  margin: 0 auto;
  padding: 2rem 1.5rem;
}

/* ============================================================
   Cards
   ============================================================ */

.card {
  background-color: var(--card-bg);
  border: 1px solid var(--border);
  border-radius: 10px;
  box-shadow: var(--card-shadow);
  padding: 1.5rem;
  margin-bottom: 1.5rem;
  transition: background-color 0.25s ease, border-color 0.25s ease;
}

/* ============================================================
   Status banners (health indicator)
   ============================================================ */

.status {
  padding: 0.75rem 1rem;
  margin-top: 1rem;
  border-radius: 6px;
  font-size: 0.9rem;
}

.status.ok {
  background-color: #d4edda;
  color: #155724;
  border: 1px solid #c3e6cb;
}

.status.error {
  background-color: #f8d7da;
  color: #721c24;
  border: 1px solid #f5c6cb;
}

:root[data-theme="dark"] .status.ok {
  background-color: #1a3a2a;
  color: #6fde9e;
  border-color: #2a5a40;
}

:root[data-theme="dark"] .status.error {
  background-color: #3a1a1a;
  color: #f08080;
  border-color: #5a2a2a;
}

/* ============================================================
   Section headers
   ============================================================ */

.section-header {
  margin-bottom: 1.5rem;
}

.section-header h1 {
  font-size: 1.8rem;
  font-weight: 700;
  margin: 0 0 0.25rem;
  color: var(--fg);
}

.section-header p {
  font-size: 1rem;
  color: var(--fg-muted);
  margin: 0;
}

/* ============================================================
   Footer
   ============================================================ */

.footer {
  background-color: var(--footer-bg);
  color: var(--footer-fg);
  padding: 1.25rem 1.5rem;
  text-align: center;
  font-size: 0.82rem;
  transition: background-color 0.25s ease;
}

.footer a {
  color: var(--accent);
}

/* ============================================================
   Utility
   ============================================================ */

.text-muted {
  color: var(--fg-muted);
}

.badge {
  display: inline-block;
  padding: 0.2em 0.6em;
  border-radius: 4px;
  font-size: 0.78rem;
  font-weight: 600;
  background-color: var(--badge-bg);
  color: var(--badge-fg);
}

/* ============================================================
   Statistics Cards Grid
   ============================================================ */

.stats-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(250px, 1fr));
  gap: 1.5rem;
  margin-bottom: 2rem;
}

.stat-card {
  display: flex;
  align-items: center;
  padding: 1.5rem;
  border-radius: 10px;
  box-shadow: var(--card-shadow);
  transition: transform 0.3s ease, box-shadow 0.3s ease;
  cursor: pointer;
}

.stat-card:hover {
  transform: translateY(-4px);
  box-shadow: 0 8px 16px var(--shadow);
}

.stat-icon {
  font-size: 2.5rem;
  margin-right: 1.5rem;
  display: flex;
  align-items: center;
  justify-content: center;
  width: 80px;
  height: 80px;
  border-radius: 8px;
}

.stat-content h3 {
  margin: 0 0 0.5rem;
  font-size: 0.95rem;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  opacity: 0.85;
}

.stat-number {
  margin: 0;
  font-size: 2rem;
  font-weight: 700;
}

/* Color schemes for each stat card */
.stat-stores {
  background: linear-gradient(135deg, #FF6B6B 0%, #FF8E8E 100%);
  color: #ffffff;
}

.stat-stores .stat-icon {
  background-color: rgba(255, 255, 255, 0.2);
  color: #ffffff;
}

.stat-products {
  background: linear-gradient(135deg, #4ECDC4 0%, #6FE0DD 100%);
  color: #ffffff;
}

.stat-products .stat-icon {
  background-color: rgba(255, 255, 255, 0.2);
  color: #ffffff;
}

.stat-employees {
  background: linear-gradient(135deg, #95E1D3 0%, #B5EFE1 100%);
  color: #1a1a2e;
}

.stat-employees .stat-icon {
  background-color: rgba(26, 26, 46, 0.1);
  color: #1a1a2e;
}

.stat-inventory {
  background: linear-gradient(135deg, #F38181 0%, #F5A6A6 100%);
  color: #ffffff;
}

.stat-inventory .stat-icon {
  background-color: rgba(255, 255, 255, 0.2);
  color: #ffffff;
}

/* Dark theme adjustments for stat cards */
:root[data-theme="dark"] .stat-stores {
  background: linear-gradient(135deg, #c94545 0%, #d95959 100%);
}

:root[data-theme="dark"] .stat-products {
  background: linear-gradient(135deg, #3a9b95 0%, #4db5ac 100%);
}

:root[data-theme="dark"] .stat-employees {
  background: linear-gradient(135deg, #6fb8a6 0%, #86cbb5 100%);
  color: #ffffff;
}

:root[data-theme="dark"] .stat-employees .stat-icon {
  background-color: rgba(255, 255, 255, 0.2);
  color: #ffffff;
}

:root[data-theme="dark"] .stat-inventory {
  background: linear-gradient(135deg, #c96668 0%, #d97d7e 100%);
}

/* ============================================================
   Mermaid Diagram Container
   ============================================================ */

.mermaid-container {
  display: flex;
  justify-content: center;
  align-items: center;
  padding: 1.5rem;
  overflow-x: auto;
  background-color: var(--bg-alt);
  border-radius: 8px;
  border: 1px solid var(--border);
  min-height: 400px;
}

.mermaid {
  display: flex;
  justify-content: center;
  align-items: center;
  max-width: 100%;
}

/* SVG text in Mermaid diagrams inherit text color from theme */
.mermaid svg {
  max-width: 100%;
  height: auto;
}

.mermaid text {
  fill: var(--fg);
}

.mermaid line,
.mermaid path,
.mermaid polyline,
.mermaid polygon {
  stroke: var(--fg-muted);
}

/* Dark theme adjustments for Mermaid */
:root[data-theme="dark"] .mermaid text {
  fill: var(--fg);
}

:root[data-theme="dark"] .mermaid line,
:root[data-theme="dark"] .mermaid path {
  stroke: var(--fg-muted);
}

/* ============================================================
   Products view
   ============================================================ */

.products-toolbar {
  display: flex;
  justify-content: flex-start;
}

.modal[hidden] {
  display: none;
}

.modal {
  position: fixed;
  inset: 0;
  z-index: 2000;
}

.modal__backdrop {
  position: absolute;
  inset: 0;
  background: rgba(0, 0, 0, 0.45);
}

.modal__panel {
  position: relative;
  width: min(820px, calc(100% - 2rem));
  max-height: calc(100vh - 4rem);
  overflow-y: auto;
  margin: 2rem auto;
  background: var(--card-bg);
  border: 1px solid var(--border);
  border-radius: 10px;
  box-shadow: var(--card-shadow);
  padding: 1.25rem;
}

.products-table-wrap {
  overflow-x: auto;
}

.products-table {
  width: 100%;
  border-collapse: collapse;
  min-width: 800px;
}

.products-table th,
.products-table td {
  border-bottom: 1px solid var(--border);
  padding: 0.75rem;
  text-align: left;
  vertical-align: middle;
}

.products-table th {
  font-size: 0.85rem;
  text-transform: uppercase;
  letter-spacing: 0.04em;
  color: var(--fg-muted);
}

.product-thumb {
  width: 52px;
  height: 52px;
  border-radius: 8px;
  object-fit: cover;
  border: 1px solid var(--border);
}

.color-chip {
  display: inline-block;
  width: 1rem;
  height: 1rem;
  border-radius: 3px;
  border: 1px solid var(--border);
  margin-right: 0.35rem;
  vertical-align: middle;
}

.form-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(220px, 1fr));
  gap: 1rem;
}

.form-grid label,
.form-grid fieldset {
  display: flex;
  flex-direction: column;
  gap: 0.4rem;
  margin: 0;
}

.form-grid input,
.form-grid select {
  background: var(--bg-alt);
  color: var(--fg);
  border: 1px solid var(--border);
  border-radius: 6px;
  padding: 0.5rem 0.65rem;
}

.inline-label {
  display: inline-flex;
  align-items: center;
  gap: 0.35rem;
}

.form-actions {
  margin-top: 1rem;
  display: flex;
  gap: 0.6rem;
}

.btn-primary,
.btn-secondary,
.btn-danger {
  border: 1px solid var(--btn-border);
  border-radius: 6px;
  padding: 0.45rem 0.75rem;
  cursor: pointer;
  font-weight: 600;
}

.btn-primary {
  background: var(--accent);
  color: #fff;
  border-color: var(--accent);
}

.btn-secondary {
  background: var(--bg-alt);
  color: var(--fg);
  border-color: var(--border);
}

.btn-danger {
  background: #d9534f;
  color: #fff;
  border-color: #d9534f;
}

.btn-small {
  font-size: 0.8rem;
  padding: 0.32rem 0.55rem;
}

.product-row-clickable {
  cursor: pointer;
}

.product-row-clickable:hover td {
  background-color: var(--bg-alt);
}

/* ============================================================
   Product detail view
   ============================================================ */

.product-detail-card {
  padding: 1.4rem;
}

.product-detail-hero {
  display: grid;
  grid-template-columns: minmax(220px, 320px) 1fr;
  gap: 1.5rem;
  align-items: stretch;
}

.product-detail-media {
  background: var(--bg);
  border: 1px solid var(--border);
  border-radius: 14px;
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 1rem;
  box-shadow: 0 4px 10px var(--shadow);
  min-height: 260px;
}

.product-detail-img {
  width: 100%;
  max-width: 260px;
  height: 220px;
  object-fit: cover;
  border-radius: 12px;
  transition: transform 0.22s ease;
}

.product-detail-media:hover .product-detail-img {
  transform: scale(1.05);
}

.product-detail-meta {
  display: flex;
  flex-direction: column;
  gap: 1rem;
}

.product-detail-name {
  margin: 0;
  color: var(--fg);
  font-size: 1.8rem;
}

.product-attr-list {
  list-style: none;
  margin: 0;
  padding: 0;
  display: flex;
  flex-direction: column;
  gap: 0.75rem;
}

.product-attr-item {
  display: flex;
  align-items: center;
  gap: 0.55rem;
  background: var(--bg-alt);
  border: 1px solid var(--border);
  border-radius: 10px;
  padding: 0.55rem 0.75rem;
}

.product-attr-item i {
  color: var(--accent);
  width: 1rem;
  text-align: center;
}

.attr-label {
  font-weight: 700;
  color: var(--fg);
}

.attr-value {
  margin-left: auto;
  color: var(--fg);
}

.color-attr-item .attr-value {
  margin-left: 0;
}

.product-color-swatch {
  width: 24px;
  height: 24px;
  border-radius: 6px;
  border: 1px solid var(--border);
  margin-left: auto;
  box-shadow: inset 0 0 0 1px rgba(255, 255, 255, 0.2);
}

.product-detail-actions {
  margin-top: auto;
  display: flex;
  justify-content: flex-end;
  gap: 0.55rem;
}

/* ============================================================
   Store detail scaffold
   ============================================================ */

.store-detail-card {
  padding: 1.4rem;
}

.store-detail-hero {
  display: grid;
  grid-template-columns: minmax(220px, 320px) 1fr;
  gap: 1.5rem;
  align-items: stretch;
}

.store-detail-media {
  background: var(--bg);
  border: 1px solid var(--border);
  border-radius: 14px;
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 1rem;
  box-shadow: 0 4px 10px var(--shadow);
  min-height: 260px;
  overflow: hidden;
}

.store-detail-img {
  width: 100%;
  max-width: 260px;
  height: 220px;
  object-fit: cover;
  border-radius: 12px;
  transition: transform 0.35s ease;
}

.store-detail-img-rotator {
  display: inline-block;
  transform-origin: center;
}

.store-detail-media:hover .store-detail-img {
  transform: scale(1.08);
}

.store-detail-media:hover .store-detail-img-rotator {
  animation: store-photo-spin-360 0.9s linear;
}

@keyframes store-photo-spin-360 {
  from {
    transform: rotate(0deg);
  }
  to {
    transform: rotate(360deg);
  }
}

.store-detail-meta {
  display: flex;
  flex-direction: column;
  gap: 1rem;
}

.store-detail-map {
  width: 100%;
  height: 340px;
  border: 1px solid var(--border);
  border-radius: 10px;
  overflow: hidden;
}

.stores-map-header {
  margin-bottom: 1rem;
}

.stores-map-card {
  border: 1px solid var(--border);
  border-radius: 12px;
  overflow: hidden;
  box-shadow: var(--card-shadow);
  background: var(--card-bg);
}

.stores-map-canvas {
  width: 100%;
  height: calc(100vh - 15rem);
  min-height: 520px;
}

.store-map-marker-wrapper {
  background: transparent;
  border: none;
}

.store-map-marker {
  width: 54px;
  height: 54px;
  border-radius: 999px;
  border: 3px solid #ffffff;
  overflow: hidden;
  box-shadow: 0 4px 12px rgba(15, 23, 42, 0.35);
  transform: translateY(-6px);
}

.store-map-marker img {
  width: 100%;
  height: 100%;
  object-fit: cover;
  display: block;
}

.store-map-tooltip .leaflet-tooltip {
  border: 1px solid var(--border);
  background: var(--card-bg);
  color: var(--fg);
  box-shadow: var(--card-shadow);
  border-radius: 12px;
  padding: 0;
}

.store-map-tooltip.leaflet-tooltip-top:before {
  border-top-color: var(--border);
}

.store-map-tooltip-card {
  width: min(320px, 72vw);
}

.store-map-tooltip-image {
  width: 100%;
  height: 120px;
  object-fit: cover;
  display: block;
}

.store-map-tooltip-body {
  padding: 0.65rem 0.75rem 0.75rem;
}

.store-map-tooltip-body h3 {
  margin: 0 0 0.35rem;
  font-size: 1rem;
}

.store-map-tooltip-body p {
  margin: 0.22rem 0;
  color: var(--fg-muted);
  font-size: 0.86rem;
  line-height: 1.35;
}

.store-map-tooltip-body p i {
  color: var(--accent);
  margin-right: 0.25rem;
}

.store-map-flag {
  width: 20px;
  height: auto;
  vertical-align: -3px;
  margin-right: 0.22rem;
}

.store-map-tooltip-hint {
  margin-top: 0.5rem !important;
  font-weight: 600;
  color: var(--fg) !important;
}

.store-map-empty-msg {
  background: var(--card-bg);
  color: var(--fg);
  border: 1px solid var(--border);
  border-radius: 8px;
  padding: 0.55rem 0.75rem;
  box-shadow: var(--card-shadow);
  font-size: 0.85rem;
}

@media (max-width: 768px) {
  .stores-map-canvas {
    height: calc(100vh - 12.5rem);
    min-height: 460px;
  }
}

.store-3d-viewer {
  position: relative;
  width: 100%;
  margin-top: 0.75rem;
  border: 1px solid var(--border);
  border-radius: 12px;
  background: color-mix(in srgb, var(--bg-alt) 86%, var(--accent) 14%);
  overflow: hidden;
}

.store-3d-viewer__canvas {
  width: 100%;
  height: clamp(320px, 48vw, 620px);
  min-height: 320px;
}

.store-3d-canvas {
  display: block;
  width: 100%;
  height: 100%;
}

.store-3d-label-layer {
  pointer-events: none;
}

.store-3d-label {
  display: inline-flex;
  align-items: center;
  gap: 0.35rem;
  padding: 0.28rem 0.48rem;
  border-radius: 8px;
  border: 1px solid rgba(30, 41, 59, 0.16);
  background: rgba(248, 250, 252, 0.9);
  color: #1e293b;
  font-size: 0.68rem;
  font-weight: 700;
  white-space: nowrap;
  box-shadow: 0 3px 10px rgba(15, 23, 42, 0.2);
  backdrop-filter: blur(3px);
}

.store-3d-label.dark {
  background: rgba(15, 23, 42, 0.88);
  color: #e2e8f0;
  border-color: rgba(148, 163, 184, 0.34);
  box-shadow: 0 4px 14px rgba(2, 6, 23, 0.45);
}

.store-3d-tooltip {
  position: absolute;
  z-index: 12;
  max-width: min(92%, 460px);
  pointer-events: none;
  background: rgba(15, 23, 42, 0.92);
  color: #f8fafc;
  border-radius: 8px;
  padding: 0.45rem 0.6rem;
  font-size: 0.78rem;
  line-height: 1.4;
  box-shadow: 0 5px 14px rgba(15, 23, 42, 0.3);
}

:root[data-theme="dark"] .store-3d-tooltip {
  background: rgba(248, 250, 252, 0.92);
  color: #0f172a;
  box-shadow: 0 5px 16px rgba(2, 6, 23, 0.52);
}

.store-3d-fallback {
  position: absolute;
  inset: auto 0 0 0;
  margin: 0;
  padding: 0.6rem 0.75rem;
  background: color-mix(in srgb, var(--card-bg) 82%, transparent);
  border-top: 1px solid var(--border);
}

.inventory-header-row {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 0.75rem;
  margin-bottom: 1rem;
}

.inventory-store-table {
  width: 100%;
  border-collapse: collapse;
  min-width: 980px;
}

.inventory-store-table th,
.inventory-store-table td {
  border-bottom: 1px solid var(--border);
  padding: 0.6rem 0.7rem;
  text-align: left;
  vertical-align: middle;
}

.inventory-store-table th {
  font-size: 0.84rem;
  text-transform: uppercase;
  letter-spacing: 0.03em;
  color: var(--fg-muted);
}

.inventory-shelf-group td {
  background: color-mix(in srgb, var(--accent) 8%, var(--card-bg));
}

.inventory-shelf-header {
  display: grid;
  grid-template-columns: 1fr auto auto;
  align-items: center;
  gap: 0.8rem;
}

.inventory-shelf-title {
  display: inline-flex;
  align-items: center;
  gap: 0.6rem;
  flex-wrap: wrap;
}

.inventory-shelf-progress-wrap {
  display: inline-flex;
  align-items: center;
  gap: 0.45rem;
}

.inventory-shelf-progress {
  width: 170px;
  height: 10px;
  border-radius: 999px;
  overflow: hidden;
  border: 1px solid var(--border);
  background: var(--bg-alt);
}

.inventory-shelf-progress span {
  display: block;
  height: 100%;
}

.fill-low {
  background: #dc2626;
}

.fill-mid {
  background: #d97706;
}

.fill-high {
  background: #1f9d55;
}

.inventory-progress-label {
  font-size: 0.78rem;
  color: var(--fg-muted);
}

.inventory-shelf-actions {
  display: inline-flex;
  gap: 0.4rem;
}

.inventory-item-row .inventory-actions {
  white-space: nowrap;
}

/* ============================================================
   Product inventory table detail
   ============================================================ */

.inventory-table {
  width: 100%;
  border-collapse: collapse;
  table-layout: fixed;
}

.inventory-table th,
.inventory-table td {
  border-bottom: 1px solid var(--border);
  padding: 0.55rem 0.7rem;
  vertical-align: middle;
}

.inventory-table th {
  color: var(--fg-muted);
  font-size: 0.84rem;
  text-transform: uppercase;
  letter-spacing: 0.04em;
}

.inventory-group-header td {
  background: color-mix(in srgb, var(--accent) 9%, var(--card-bg));
  font-weight: 700;
  min-height: 64px;
  border-bottom: 1px solid var(--border);
}

.inventory-group-start td {
  border-top: 10px solid var(--bg);
}

.inventory-group-header-inner {
  display: flex;
  align-items: center;
  gap: 0.6rem;
  flex-wrap: wrap;
}

.inventory-group-header-inner .btn-add-shelf {
  margin-left: auto;
}

.store-name-group {
  display: inline-flex;
  align-items: center;
  gap: 0.35rem;
}

.store-flag-sm {
  border-radius: 2px;
}

.inventory-detail-row td {
  background: var(--card-bg);
}

.inventory-detail-row td:nth-child(2) {
  padding-left: 0.7rem;
  text-align: center;
}

.inventory-table th:nth-child(2),
.inventory-table td:nth-child(2),
.inventory-table th:nth-child(3),
.inventory-table td:nth-child(3) {
  text-align: center;
}

.inventory-actions {
  text-align: right;
  white-space: nowrap;
}

.inventory-actions .btn-small {
  padding: 0.25rem 0.48rem;
}

.badge-stock,
.badge-count {
  border-radius: 999px;
  border: 0;
  font-weight: 700;
  padding: 0.2rem 0.6rem;
}

.badge-stock-high,
.badge-count.badge-stock-high {
  background: #1f9d55;
  color: #fff;
}

.badge-stock-medium,
.badge-count.badge-stock-medium {
  background: #d97706;
  color: #fff;
}

.badge-stock-low,
.badge-count.badge-stock-low {
  background: #dc2626;
  color: #fff;
}

.add-shelf-inline {
  margin-top: 0.65rem;
  padding: 0.65rem;
  border: 1px dashed var(--border);
  border-radius: 10px;
  background: var(--card-bg);
}

.add-shelf-inline select,
.add-shelf-inline input {
  background: var(--bg-alt);
  color: var(--fg);
  border: 1px solid var(--border);
  border-radius: 6px;
  padding: 0.35rem 0.45rem;
}

@media (max-width: 900px) {
  .product-detail-hero {
    grid-template-columns: 1fr;
  }

  .store-detail-hero {
    grid-template-columns: 1fr;
  }

  .inventory-header-row {
    flex-direction: column;
    align-items: flex-start;
  }

  .inventory-shelf-header {
    grid-template-columns: 1fr;
    align-items: flex-start;
  }

  .inventory-shelf-actions {
    flex-wrap: wrap;
  }

  .product-detail-media {
    min-height: 200px;
  }

  .store-detail-media {
    min-height: 200px;
  }

  .product-detail-img {
    max-width: 100%;
    width: min(100%, 320px);
    height: 200px;
  }

  .store-detail-img {
    max-width: 100%;
    width: min(100%, 320px);
    height: 200px;
  }

  .product-detail-actions {
    justify-content: flex-start;
  }
}

{% extends "base.html" %}

{% block title %}Stores Map — FIWARE Smart Store{% endblock %}

{% block content %}
<div class="section-header stores-map-header">
  <h1 data-i18n="page_stores_map_title">Mapa de Tiendas</h1>
  <p data-i18n="page_stores_map_subtitle">Vista geográfica de todas las tiendas</p>
</div>

<div class="stores-map-card">
  <div id="stores-map-canvas" class="stores-map-canvas" role="region" aria-label="Stores map"></div>
</div>
{% endblock %}

{% block extra_scripts %}
<script>
  (function () {
    'use strict';

    var stores = {{ stores|default([], true)|tojson }};
    var mapEl = document.getElementById('stores-map-canvas');
    if (!mapEl || typeof L === 'undefined') return;

    function t(key, fallback) {
      if (!window.i18n || typeof window.i18n.t !== 'function') return fallback || key;
      var text = window.i18n.t(key);
      return text === key ? (fallback || key) : text;
    }

    function escapeHtml(value) {
      return String(value == null ? '' : value)
        .replace(/&/g, '&amp;')
        .replace(/</g, '&lt;')
        .replace(/>/g, '&gt;')
        .replace(/\"/g, '&quot;')
        .replace(/'/g, '&#39;');
    }

    function storeFallbackImage(store) {
      var countryCode = String(store && store.countryCode || '').toUpperCase();
      var imagesByCountry = {
        DE: 'https://images.unsplash.com/photo-1556742049-0cfed4f6a45d',
        ES: 'https://images.unsplash.com/photo-1542838132-92c53300491e',
        FR: 'https://images.unsplash.com/photo-1604719312566-8912e9227c6a',
        PT: 'https://images.unsplash.com/photo-1578916171728-46686eac8d58',
        IT: 'https://images.unsplash.com/photo-1579113800032-c38bd7635818',
        UK: 'https://images.unsplash.com/photo-1514933651103-005eec06c04b',
        US: 'https://images.unsplash.com/photo-1441986300917-64674bd600d8'
      };
      return imagesByCountry[countryCode] || 'https://images.unsplash.com/photo-1556740749-887f6717d7e4';
    }

    function parseLocation(location) {
      if (!location || typeof location !== 'object') return null;
      var coords = location.coordinates;
      if (!Array.isArray(coords) || coords.length < 2) return null;
      var lon = Number(coords[0]);
      var lat = Number(coords[1]);
      if (Number.isNaN(lat) || Number.isNaN(lon)) return null;
      if (lat < -90 || lat > 90 || lon < -180 || lon > 180) return null;
      return { lat: lat, lon: lon };
    }

    function formatAddress(address) {
      if (!address) return '-';
      if (typeof address === 'string') return address;
      if (typeof address !== 'object') return '-';

      var parts = [
        address.streetAddress,
        address.addressLocality,
        address.addressRegion,
        address.postalCode
      ].filter(Boolean);

      return parts.length ? parts.join(', ') : '-';
    }

    function formatHumidity(value) {
      var parsed = Number(value);
      if (Number.isNaN(parsed)) return '-';
      return (parsed * 100).toFixed(0) + '%';
    }

    function formatTemperature(value) {
      var parsed = Number(value);
      if (Number.isNaN(parsed)) return '-';
      return parsed.toFixed(1) + '°C';
    }

    function isDarkTheme() {
      return document.documentElement.getAttribute('data-theme') === 'dark';
    }

    var lightTileUrl = 'https://{s}.basemaps.cartocdn.com/light_all/{z}/{x}/{y}{r}.png';
    var darkTileUrl = 'https://{s}.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png';
    var tileAttribution = '&copy; OpenStreetMap contributors &copy; CARTO';

    var map = L.map(mapEl, {
      zoomControl: true,
      worldCopyJump: true
    });

    var tileLayer = null;
    function refreshTileLayer() {
      var nextUrl = isDarkTheme() ? darkTileUrl : lightTileUrl;
      if (tileLayer) map.removeLayer(tileLayer);
      tileLayer = L.tileLayer(nextUrl, {
        maxZoom: 19,
        attribution: tileAttribution
      });
      tileLayer.addTo(map);
    }

    refreshTileLayer();

    function markerIcon(imageUrl) {
      return L.divIcon({
        className: 'store-map-marker-wrapper',
        iconSize: [54, 54],
        iconAnchor: [27, 44],
        popupAnchor: [0, -36],
        html: '<div class="store-map-marker">'
          + '<img src="' + escapeHtml(imageUrl) + '" alt="Store" loading="lazy" referrerpolicy="no-referrer" />'
          + '</div>'
      });
    }

    function tooltipHtml(store) {
      var image = store.image || storeFallbackImage(store);
      var countryCode = String(store.countryCode || '').toUpperCase();
      var flagUrl = countryCode && /^[A-Z]{2}$/.test(countryCode)
        ? 'https://flagcdn.com/w40/' + countryCode.toLowerCase() + '.png'
        : '';

